#include <stdio.h>
#include <stdlib.h>

typedef long long int ll;

ll t, n, q, a[100009], x, ans[100009];
struct Pair {
    ll first;
    ll second;
};

struct Pair qr[100009];

int comparePairs(const void *a, const void *b) {
    struct Pair *pairA = (struct Pair *)a;
    struct Pair *pairB = (struct Pair *)b;
    return (pairA->first > pairB->first) - (pairA->first < pairB->first);
}

int compareLL(const void *a, const void *b) {
    return (*(ll *)a > *(ll *)b) - (*(ll *)a < *(ll *)b);
}

int main() {
    scanf("%lld", &t);
    while (t--) {
        ll cur = 0;
        ll prev = 0, presum = 0;

        scanf("%lld %lld", &n, &q);
        for (ll i = 1; i <= n; i++)
            scanf("%lld", &a[i]);
        for (ll i = 0; i < q; i++) {
            scanf("%lld", &x);
            qr[i].first = x;
            qr[i].second = i;
        }

        qsort(a + 1, n, sizeof(ll), compareLL);
        qsort(qr, q, sizeof(struct Pair), comparePairs);

        for (ll i = 1; ; i++) {
            ll fir = qr[cur].first;
            while (a[i] < fir && i < n + 1) {
                presum += (fir - a[i]);
                i++;
            }
            i--;
            while (presum > prev) {
                prev++;
                presum -= (fir - a[prev]);
            }
            ans[qr[cur].second] = n - prev;

            if (cur == q - 1)
                break;

            presum += (i - prev) * (qr[cur + 1].first - fir);
            cur++;
        }

        for (ll i = 0; i < q; i++)
            printf("%lld\n", ans[i]);
    }
    return 0;
}

